#include <bits/stdc++.h>
using namespace std;
struct Node{
    int data;
    Node* next;
};
int n,m,t,g[100005];
struct _queue{
    Node *head,*tail,*last[302];
    void clear(){
        head=NULL;
        tail=NULL;
        memset(last,NULL,sizeof(last));
    }
    void push(int x){
        Node* p=new Node;
        p->data=x;
        p->next=NULL;
        if(head==NULL)
        	head=tail=last[g[x]]=p;
        else if(last[g[x]]==NULL)
        	tail->next=p,tail=last[g[x]]=p;
        else{
        	p->next=last[g[x]]->next;
        	last[g[x]]->next=p;
        	last[g[x]]=p;
        	if(p->next==NULL)
        		tail=p;
		}
    }
    void pop(){
    	if(last[g[head->data]]==head)
    		last[g[head->data]]=NULL;
    	printf("%d\n",head->data);
    	head=head->next;
    	if(head==NULL)
    		tail=head;
	}
}q;
int main(){
    scanf("%d%d",&n,&m);
    for(int i=0;i<n;i++)
    	scanf("%d",&g[i]);
    scanf("%d",&t);
    while(t--){
    	string op;
    	cin>>op;
    	if(op=="push"){
    		int x;
    		scanf("%d",&x);
    		q.push(x);
		}else{
			q.pop();
		}
	}
    return 0;
}
